def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    best_node = None
    min_time = float('inf')

    for i, customer in enumerate(unvisited_customers):
        total_time = np.linalg.norm(cur_truck_pos - customer) + np.linalg.norm(customer - depot_pos)
        for truck_pos in all_truck_pos:
            dist_to_truck = np.linalg.norm(truck_pos - customer)
            if dist_to_truck < total_time:
                total_time += total_time - dist_to_truck
        if total_time < min_time:
            min_time = total_time
            best_node = i

    return best_node

import numpy as np

def calculate_distance(pos1, pos2):
    return np.linalg.norm(pos1 - pos2)

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    min_distance = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            distance = calculate_distance(truck_pos, customer_pos)
            if distance < min_distance:
                min_distance = distance
                best_node = i

    del unvisited_customers[best_node]
    return best_node
